package com.cognizant.springtesting;import static org.mockito.Mockito.*;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;import java.util.NoSuchElementException;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;import org.springframework.boot.test.mock.mockito.MockBean;import org.springframework.context.annotation.Import;import org.springframework.test.web.servlet.MockMvc;@WebMvcTest(UserController.class)@Import(GlobalExceptionHandler.class)public class UserControllerExceptionTest {@Autowired MockMvc mockMvc;@MockBean UserService userService;@Test void testExceptionHandling() throws Exception{when(userService.getUserById(99L)).thenThrow(new NoSuchElementException("User not found"));mockMvc.perform(get("/users/99")).andExpect(status().isNotFound()).andExpect(content().string("User not found"));verify(userService).getUserById(99L);}}
